+    ensure_min_len(wal_header, WAL_HEADER_SIZE, "WAL header")?;
+    write_be_u32_at(wal_header, WAL_HEADER_SALT1_OFFSET, salts.salt1);
+    write_be_u32_at(wal_header, WAL_HEADER_SALT2_OFFSET, salts.salt2);
